# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os
from pathlib import Path

def delete_user_file(filename):
    # Create the filepath by combining 'uploads/' with the provided filename
    file_path = str(Path(__file__).parent / f"uploads/{filename}")
    
    try: 
        # Try deleting the file at the specified location.
        os.remove(file_path)
        
        print('File deleted successfully')
        
    except FileNotFoundError: 
        # If the file was not found, inform the user.
        print("No such file exists")